import React, { Component } from 'react';
import './SNSLink.css';

class SNSLink extends Component {
    render() {
        const {
            type,
            id,
            link,
            src
        } = this.props;

        if (type == "github") {
            const link = "https://github.com/" + id;
                const src = "./github.png"
        }

        const openWindow = () => {
            window.open(link, '_blank');
        }

        return (
            <button className="SNSBtn" onClick={openWindow}>
                <img className="logo" src={src}></img>
            </button>
        );
    }
}

export default SNSLink;
